INSERT INTO afl.season (league_id, name)
    SELECT id, 'AFL 2024' FROM afl.league WHERE name = 'AFL';

INSERT INTO afl.club_season (club_id, season_id)
    SELECT c.id, s.id FROM afl.club c
    CROSS JOIN (SELECT id FROM afl.season WHERE name = 'AFL 2024') s
    ON CONFLICT (club_id, season_id) DO NOTHING;

DO $$
DECLARE
    v_season_id  INTEGER;
    v_match_id   INTEGER;
    v_home_cm_id INTEGER;
    v_away_cm_id INTEGER;
