        (v_season_id, 'Semi Final'),
        (v_season_id, 'Preliminary Final'),
        (v_season_id, 'Grand Final');

    FOR rec IN SELECT * FROM (VALUES
        ('Opening Round', 'Brisbane Lions', 'Carlton Blues'),
        ('Opening Round', 'Collingwood Magpies', 'Greater Western Sydney Giants'),
