) AS v(player_name, club_name, round_name, kicks, handballs, marks, hitouts, tackles, goals, behinds)
JOIN afl.player p ON p.name = v.player_name
JOIN afl.player_season ps ON ps.player_id = p.id
JOIN afl.club_season cs ON ps.club_season_id = cs.id
JOIN afl.club c ON cs.club_id = c.id AND c.name = v.club_name
JOIN afl.season s ON cs.season_id = s.id AND s.name = 'AFL 2024'
JOIN afl.club_match cm ON cm.club_season_id = cs.id
JOIN afl.match m ON cm.match_id = m.id
JOIN afl.round r ON m.round_id = r.id AND r.name = v.round_name
ON CONFLICT (player_season_id, club_match_id) DO NOTHING;

